import{b as t,I as n,g as r,j as s}from"./chunks/framework.DUo3J_Qe.js";const a="/geo-ml/learning/deep-learning/neural-network.png",g=JSON.parse('{"title":"Deep Learning","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/deep-learning/introduction.md","filePath":"fr/learning/deep-learning/introduction.md"}'),i={name:"fr/learning/deep-learning/introduction.md"};function o(d,e,u,l,c,p){return n(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="deep-learning" tabindex="-1">Deep Learning <a class="header-anchor" href="#deep-learning" aria-label="Permalink to &quot;Deep Learning&quot;">​</a></h1><p>Le Deep Learning est une branche du Machine Learning basée sur des <strong>réseaux de neurones artificiels</strong> profonds.</p><div class="tip custom-block"><p class="custom-block-title">Définition</p><p>Un réseau de neurones artificiel s’inspire (de manière simplifiée) du fonctionnement du cerveau : des neurones interconnectés reçoivent des signaux en entrée, appliquent une transformation mathématique (poids + biais + fonction d’activation), et transmettent le résultat aux neurones suivants.</p></div><p><img src="'+a+'" alt="neural-network"></p><p>La différence entre un réseau classique et le Deep Learning réside dans la profondeur :</p><ul><li>Réseau peu profond (shallow) = entrée → 1 ou 2 couches cachées → sortie</li><li>Réseau profond (deep learning) = entrée → dizaines voire centaines de couches → sortie</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Plus le réseau est profond, plus il peut apprendre des représentations hiérarchiques complexes (caractéristiques simples → motifs intermédiaires → concepts abstraits).</p></div><h2 id="principaux-types-de-reseaux" tabindex="-1">Principaux types de réseaux <a class="header-anchor" href="#principaux-types-de-reseaux" aria-label="Permalink to &quot;Principaux types de réseaux&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Réseau</th><th>Nom complet</th><th>Idée clé</th><th>Usage typique</th></tr></thead><tbody><tr><td><strong>ANN</strong></td><td>Artificial Neural Network</td><td>Neurones entièrement connectés - chaque neurone reçoit tous les signaux de la couche précédente</td><td>Données tabulaires, classification générale</td></tr><tr><td><strong>CNN</strong></td><td>Convolutional Neural Network</td><td>Filtres qui glissent sur l&#39;image pour détecter des motifs locaux (bords, textures, formes)</td><td>Images, vidéos, données spatiales</td></tr><tr><td><strong>RNN</strong></td><td>Recurrent Neural Network</td><td>Boucle de mémoire interne - la sortie d&#39;un pas de temps est réinjectée en entrée du suivant</td><td>Séries temporelles, texte, audio</td></tr><tr><td><strong>LSTM</strong></td><td>Long Short-Term Memory</td><td>Variante de RNN avec une mémoire longue durée (évite l&#39;oubli des informations anciennes)</td><td>Traduction, prévision météo, speech</td></tr><tr><td><strong>Transformer</strong></td><td>—</td><td>Mécanisme d&#39;attention - chaque élément regarde tous les autres pour se contextualiser</td><td>LLMs (GPT, Claude), vision (ViT)</td></tr><tr><td><strong>GAN</strong></td><td>Generative Adversarial Network</td><td>Deux réseaux en compétition : un générateur crée des données, un discriminateur les évalue</td><td>Génération d&#39;images, augmentation de données</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Dans GeoML</p><p>On utilise un <strong>CNN</strong> comme bloc de base, intégré dans une architecture <strong>U-Net</strong> pour la segmentation sémantique. Les Transformers (ViT, SegFormer) sont une alternative plus récente mais plus gourmande en données.</p></div>',10)])])}const h=t(i,[["render",o]]);export{g as __pageData,h as default};
